import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Przesyłanie logów","description":"Jak przesyłać logi na potrzeby rozwiązywania problemów.","frontmatter":{"title":"Przesyłanie logów","description":"Jak przesyłać logi na potrzeby rozwiązywania problemów.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.8/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.8/translated/pl_pl/players/troubleshooting/uploading-logs.md","lastUpdated":1760721669000}`);var a={name:`pl_pl/1.21.8/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Przesyłanie logów <a class="header-anchor" href="#h1" aria-label="Permalink to “Przesyłanie logów”">​</a></h1><p>Podczas rozwiązywania problemów często konieczne jest udostępnienie logów, aby móc zidentyfikować przyczynę problemu.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Dlaczego warto przesyłać logi? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Dlaczego warto przesyłać logi?”">​</a></h2><p>Przesyłanie logów pozwala innym pomóc ci w rozwiązywaniu problemów znacznie szybciej niż poprzez zwykłe wklejenie logów na czat lub post na forum. Pozwala również na udostępnianie logów innym, bez konieczności ich kopiowania i wklejania.</p><p>Niektóre strony do wklejania tekstu zapewniają również podświetlanie składni logów, co ułatwia ich czytanie, oraz mogą cenzurować poufne informacje, takie jak twoja nazwa użytkownika czy informacje o systemie.</p><h2 id="crash-reports" tabindex="-1">Raporty awarii <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Raporty awarii”">​</a></h2><p>Raporty awarii są automatycznie generowane podczas awarii gry. Zawierają one jednak tylko informacje o awarii, a nie rzeczywiste logi gry. Znajdują się one w folderze <code>crash-reports</code> w katalogu gry.</p><p>Więcej informacji na temat raportów awarii znajdziesz w przewodniku <a href="./crash-reports">Raporty awarii</a>.</p><h2 id="locating-logs" tabindex="-1">Znajdowanie logów <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Znajdowanie logów”">​</a></h2><p>Ten przewodnik dotyczy oficjalnego launchera Minecrafta (powszechnie określanego jako „vanilla launcher”) — w przypadku innych launcherów należy zapoznać się z ich dokumentacją.</p><p>Logi znajdują się w folderze <code>logs</code> w katalogu gry, który można znaleźć w następujących lokalizacjach dla poszczególnych systemów operacyjnych:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Najnowszy log ma nazwę <code>latest.log</code>, a poprzednie logi nazywane są według wzorca <code>rrrr-mm-dd_numer.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Przesyłanie logów online <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Przesyłanie logów online”">​</a></h2><p>Logi można przesłać do różnych usług, takich jak:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};